mapper.select:
SELECT id, parent_level_id, child_level_id, child_qty, is_fixed_qty, tare_weight, status, deleted, created_at, updated_at, created_by, updated_by FROM packaging_relation WHERE deleted = 0
AND parent_level_id = #{parentLevelId}
AND status = #{status}
ORDER BY parent_level_id ASC, id ASC
